import React from "react";
import "../HeaderBar/HeaderBar.css";
import { Link } from "react-router-dom";

export default function HeaderBar() {
  return (
    <>
      <div className="headerBar">
        <Link to="/login">Login</Link>
        <Link to="/register">Register</Link>
      </div>
    </>
  );
}
